import{c as e,Q as r,j as t,m as s}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"How do I configure SSO?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/portal/configure-sso.md","filePath":"guide/recipes/portal/configure-sso.md","lastUpdated":1779094756000}'),i={name:"guide/recipes/portal/configure-sso.md"};function n(a,o,l,d,c,g){return r(),t("div",null,[...o[0]||(o[0]=[s('<h1 id="how-do-i-configure-sso" tabindex="-1">How do I configure SSO? <a class="header-anchor" href="#how-do-i-configure-sso" aria-label="Permalink to &quot;How do I configure SSO?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Owner</strong> or <strong>Admin</strong></p></div><p>Add an identity provider (Google Workspace, Microsoft Entra / Azure AD, or any OIDC provider) so your users sign in through your own identity system instead of a Console password.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Settings</strong> in the sidebar and switch to the <strong>Security</strong> tab.</li><li>Scroll to <strong>Identity Providers</strong> and click <strong>Add Provider</strong>.</li><li>Choose the type: <ul><li><strong>Google</strong> — for Google Workspace.</li><li><strong>Microsoft / Azure</strong> — for Microsoft Entra ID. You&#39;ll also need to supply the Azure tenant ID.</li><li><strong>Custom OIDC</strong> — for any other OIDC provider.</li></ul></li><li>Fill in <strong>Name</strong>, <strong>Client ID</strong>, and <strong>Client Secret</strong> from your provider&#39;s app registration.</li><li>(Optional) Set <strong>Scopes</strong> if your provider needs more than <code>openid email profile</code>.</li><li>Click <strong>Add</strong>.</li><li>Use the <strong>Test</strong> button on the provider row to verify the configuration before letting users in.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The new provider appears in the <strong>Identity Providers</strong> table. Users whose email matches an <a href="./domain-login-rules">auth rule</a> will be sent to that provider at sign-in instead of the password screen.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./domain-login-rules">How do I route logins by email domain?</a></li><li><a href="./enforce-mfa">How do I enforce MFA across my organisation?</a></li></ul>',9)])])}const h=e(i,[["render",n]]);export{p as __pageData,h as default};
